先停一下——**把 refresh token 存 localStorage 是个安全问题，不建议这样做。**

Refresh token 的威胁模型和 access token 不同：access token 短命，泄露损失有限；refresh token 长命（天到周级别），一旦被 XSS 窃取，攻击者可以持续换新 token，直到你主动撤销。LocalStorage 对 XSS 完全暴露。

推荐方案：**refresh token 存 `HttpOnly; Secure; SameSite=Strict` cookie**，access token 存内存（变量）。

- Cookie 对 JS 不可见，XSS 无法读取
- `SameSite=Strict` 防 CSRF
- 刷新页面时，access token 丢失但 cookie 还在，静默换新即可

---

## 实现逻辑

### 后端（以 Node/Express 为例）

```js
// 登录：下发两个 token
app.post('/auth/login', async (req, res) => {
  const user = await validateCredentials(req.body);
  if (!user) return res.status(401).json({ error: 'Invalid credentials' });

  const accessToken = signAccessToken(user.id);   // 15min
  const refreshToken = signRefreshToken(user.id); // 7d

  await saveRefreshToken(user.id, refreshToken);  // 存 DB，支持撤销

  res.cookie('refresh_token', refreshToken, {
    httpOnly: true,
    secure: true,          // 只走 HTTPS
    sameSite: 'Strict',
    maxAge: 7 * 24 * 60 * 60 * 1000,
  });

  res.json({ accessToken });
});

// 换新 access token
app.post('/auth/refresh', async (req, res) => {
  const refreshToken = req.cookies.refresh_token;
  if (!refreshToken) return res.status(401).json({ error: 'No refresh token' });

  let payload;
  try {
    payload = verifyRefreshToken(refreshToken);
  } catch {
    return res.status(401).json({ error: 'Invalid refresh token' });
  }

  const stored = await getRefreshToken(payload.userId);
  if (stored !== refreshToken) {
    // token 已被撤销或轮换
    return res.status(401).json({ error: 'Refresh token revoked' });
  }

  // 轮换：每次 refresh 换新的 refresh token（可选但推荐）
  const newRefreshToken = signRefreshToken(payload.userId);
  await saveRefreshToken(payload.userId, newRefreshToken);

  res.cookie('refresh_token', newRefreshToken, { httpOnly: true, secure: true, sameSite: 'Strict', maxAge: 7 * 24 * 60 * 60 * 1000 });
  res.json({ accessToken: signAccessToken(payload.userId) });
});

// 登出：清 cookie + 撤销 DB 记录
app.post('/auth/logout', async (req, res) => {
  const refreshToken = req.cookies.refresh_token;
  if (refreshToken) {
    const payload = verifyRefreshToken(refreshToken).catch(() => null);
    if (payload) await deleteRefreshToken(payload.userId);
  }
  res.clearCookie('refresh_token');
  res.sendStatus(204);
});
```

### 前端：内存存 access token + 自动续期

```js
let accessToken = null; // 内存，刷新页面会清空——这是预期行为

async function fetchWithAuth(url, options = {}) {
  if (!accessToken) {
    // 页面刷新后先静默换 token
    accessToken = await refreshAccessToken();
    if (!accessToken) {
      redirectToLogin();
      return;
    }
  }

  let res = await fetch(url, {
    ...options,
    headers: { ...options.headers, Authorization: `Bearer ${accessToken}` },
  });

  if (res.status === 401) {
    // access token 过期，换新的再重试一次
    accessToken = await refreshAccessToken();
    if (!accessToken) { redirectToLogin(); return; }

    res = await fetch(url, {
      ...options,
      headers: { ...options.headers, Authorization: `Bearer ${accessToken}` },
    });
  }

  return res;
}

async function refreshAccessToken() {
  const res = await fetch('/auth/refresh', {
    method: 'POST',
    credentials: 'include', // 带上 cookie
  });
  if (!res.ok) return null;
  const data = await res.json();
  return data.accessToken;
}
```

---

## 你方案的问题对比

| | localStorage refresh token | HttpOnly cookie refresh token |
|---|---|---|
| XSS 可读 | ✅ 可读，可直接窃取 | ❌ JS 不可见 |
| CSRF | ❌ 不受影响 | 需 SameSite 或 CSRF token |
| 刷新页面不掉 | ✅ | ✅（静默换 access token）|
| 可撤销 | 需后端 DB | 需后端 DB |

刷新页面不掉线的需求完全可以用 HttpOnly cookie 满足，不需要 localStorage。

⚠️ **风险**：如果你们的站点有任何第三方脚本（统计、广告、客服插件），localStorage 里的 refresh token 就是裸奔的——这些脚本全都能读到。

