    key="refresh_token",
    value=refresh_token,
    httponly=True,
    secure=True,         # 仅 HTTPS
    samesite="Strict",
    max_age=60 * 60 * 24 * 7  # 7天
)
return {"access_token": access_token}  # 只在 body 返回 access token
```

