  const token = req.cookies.refreshToken
  if (!token) return res.status(401).json({ error: 'no refresh token' })

  try {
    const payload = jwt.verify(token, REFRESH_SECRET)
    const accessToken = jwt.sign({ userId: payload.userId }, ACCESS_SECRET, { expiresIn: '15m' })
    res.json({ accessToken })
  } catch {
    res.status(401).json({ error: 'invalid refresh token' })
  }
})

// 登出：清除 cookie
app.post('/auth/logout', (req, res) => {
  res.clearCookie('refreshToken')
  res.sendStatus(204)
})
```

**客户端（内存存 access token + 自动刷新）：**

```js
let accessToken = null

async function fetchWithAuth(url, options = {}) {
  if (!accessToken) {
    accessToken = await refreshAccessToken()
  }

  const res = await fetch(url, {
    ...options,
    headers: { ...options.headers, Authorization: `Bearer ${accessToken}` },
  })

  // access token 过期，刷新后重试一次
  if (res.status === 401) {
    accessToken = await refreshAccessToken()
    return fetch(url, {
      ...options,
      headers: { ...options.headers, Authorization: `Bearer ${accessToken}` },
    })
  }

  return res
}

async function refreshAccessToken() {
  const res = await fetch('/auth/refresh', { method: 'POST', credentials: 'include' })
  if (!res.ok) {
    // refresh token 也失效了，跳登录
    window.location.href = '/login'
    return null
  }
  const data = await res.json()
  return data.accessToken
}
```

`credentials: 'include'` 让 fetch 自动带上 cookie。刷新页面后 accessToken 内存为空，首次请求触发 `/auth/refresh`，cookie 还在，静默续签——用户无感知。

