// auth/store.ts
type State = { user: User | null; loading: boolean }
type Action = { type: 'SET_USER'; user: User } | { type: 'LOGOUT' }

const AuthContext = createContext<{ state: State; dispatch: Dispatch<Action> } | null>(null)

function reducer(state: State, action: Action): State {
  switch (action.type) {
    case 'SET_USER': return { ...state, user: action.user, loading: false }
    case 'LOGOUT':   return { user: null, loading: false }
  }
}

export function AuthProvider({ children }: { children: ReactNode }) {
  const [state, dispatch] = useReducer(reducer, { user: null, loading: true })
  return <AuthContext.Provider value={{ state, dispatch }}>{children}</AuthContext.Provider>
}

export function useAuth() {
  const ctx = useContext(AuthContext)
  if (!ctx) throw new Error('useAuth must be used within AuthProvider')
  return ctx
}
